noncompliant:
void doSomething(A& a);
void f() {
  A* a = nullptr;
  // ...
  doSomething(*a); // Noncompliant: dereferencing null pointer
}

void processObject(Object& obj);
void badFunction() {
  Object* ptr = getObjectPointer(); // might return nullptr
  processObject(*ptr); // Noncompliant: no null check
}

compliant:
void doSomething(A& a);
void f() {
  A* a = nullptr;
  if (a != nullptr) {
    doSomething(*a); // Compliant: checked for null
  }
}

void processObject(Object& obj);
void goodFunction() {
  Object* ptr = getObjectPointer();
  if (ptr) {
    processObject(*ptr); // Compliant: null check before dereference
  }
}

// Alternative: use references when object must exist
void anotherGoodFunction(Object& obj) {
  processObject(obj); // Compliant: reference guarantees valid object
}
